<template lang="pug">
  v-app
    v-slide-y-transition(v-if="$vuetify.breakpoint.mdAndUp")
      FullToolbar(v-if="full")
      SemiToolbar(v-else)
    MobileToolbar(v-else)
    v-main(style="background: #e6e7e8;" v-scroll="onScroll")
      Banner(v-if="$vuetify.breakpoint.mdAndUp")
      MainContent
</template>

<script>
import Banner from './components/Banner.vue'
import FullToolbar from './components/FullToolbar.vue'
import SemiToolbar from './components/SemiToolbar.vue'
import MobileToolbar from './components/MobileToolbar.vue'
import MainContent from './components/MainContent.vue'

export default {
  components: {
    Banner, FullToolbar, SemiToolbar, MobileToolbar, MainContent
  },
  data: () => ({
    full: true,
  }),
  mounted () {
  },
  methods: {
    onScroll (e) {
      const vm = this
      const y = e.currentTarget.scrollY
      if (y > 150) {
        vm.full = false
      } else if (y < 10) {
        vm.full = true
      }
    },
  },
};
</script>

