<template lang="pug">
  v-menu(offset-y transition="slide-y-transition" max-width="120")
    template(v-slot:activator="{ on, attrs }")
      div(v-bind="attrs" v-on="on")
        v-btn(text small plain) {{ current.text }}
          v-icon(x-small) mdi-chevron-down
    v-list
      v-list-item(v-for="(l, i) in locales" :key="i" @click="setLocale(l)")
        .caption {{ l.text }}
</template>

<script>
export default {
  data () {
    return {
      locales: [
        { text: 'English', value: 'en' },
        { text: '简体中文', value: 'zh-Hans' },
        { text: '繁體中文', value: 'zh-Hant' },
        { text: '日本語', value: 'ja' },
      ],
    }
  },
  mounted () {
  },
  computed: {
    current () {
      return this.getLocale()
    }
  },
  methods: {
    setLocale (val) {
      this.$i18n.locale = val.value
    },
    getLocale () {
      const vm = this
      return vm.locales.filter(i => i.value === vm.$i18n.locale)[0]
    }
  },
}
</script>
