<template lang="pug">
  v-row.no-gutters(style="width: 100%; background: white;")
    v-container(v-resize="onResize")
      v-row
        v-col(cols="2")
          v-chip(color="pink" small label dark outlined)
           .caption(v-if="breaking") {{ $t('$m.breaking') }}
           .caption(v-else) {{ $t('$m.statement') }}
        v-col
          .marquee1(:style="style")
            .caption {{ $t('$m.notice') }}
        v-col(cols="3")
          span.float-right.pink--text.caption.mt-1 {{ $d(new Date(), 'long', $i18n.locale) }}
</template>

<script>
export default {
  data () {
    return {
      breaking: false,
      noticeWidth: 750,
    }
  },
  mounted () {
  },
  computed: {
    style () {
      return {
        width: this.noticeWidth + 'px'
      }
    },
  },
  methods: {
    onResize () {
      const vm = this
      const bp = this.$vuetify.breakpoint
      vm.noticeWidth = bp.name === 'lg' ? 750 : 500
    }
  },
}
</script>

<style>
.marquee1 {
  margin: 0 auto;
  white-space: nowrap;
  overflow: hidden;
  position: absolute;
}

.marquee1 .caption {
  display: inline-block;
  padding-left: 100%;
  animation: marquee1 25s linear infinite;
}

@keyframes marquee1 {
  0% {
    transform: translate(0, 0);
  }
  100% {
    transform: translate(-100%, 0);
  }
}
</style>
